using sv_875e10040b0f4dbdb6f581e78b168275.Models;

namespace sv_875e10040b0f4dbdb6f581e78b168275.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Pasta Carbonara", "Creamy Roman pasta with guanciale, Pecorino Romano, and black pepper.", 25),
            new(3, "Risotto alla Milanese", "Saffron-infused Arborio rice cooked slowly in broth with Parmigiano-Reggiano.", 45),
            new(4, "Tiramisu", "Layered dessert of espresso-soaked ladyfingers and mascarpone cream.", 40),
        },
        [2] = new List<Recipe>
        {
            new(5, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts, Sichuan peppercorns, and dried chili peppers.", 35),
            new(6, "Mapo Tofu", "Silken tofu in a fiery sauce of doubanjiang, fermented black beans, and ground pork.", 20),
            new(7, "Xiaolongbao", "Steamed soup dumplings filled with seasoned pork and rich broth.", 90),
        },
        [3] = new List<Recipe>
        {
            new(8, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion on corn tortillas.", 60),
            new(9, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(10, "Churros", "Fried dough pastries coated in cinnamon sugar, served with chocolate sauce.", 35),
            new(11, "Pozole Rojo", "Hearty hominy stew with pork in a rich guajillo and ancho chili broth.", 120),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_875e10040b0f4dbdb6f581e78b168275.Models
@using sv_875e10040b0f4dbdb6f581e78b168275.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes — Cuisine @CuisineId</h1>

@if (_error is not null)
{
    <div class="alert alert-danger d-flex align-items-center justify-content-between" role="alert">
        <span>@_error</span>
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="Retry">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <div class="alert alert-info py-1 px-2 d-inline-block" role="status">Refreshing…</div>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;
    private CancellationTokenSource? _cts;
    private bool _disposed;

    private IEnumerable<Recipe> DisplayedRecipes =>
        _recipes is null
            ? Enumerable.Empty<Recipe>()
            : string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
                ? _recipes.OrderBy(r => r.PrepTimeMinutes)
                : _recipes.OrderByDescending(r => r.Id);

    public override async Task SetParametersAsync(ParameterView parameters)
    {
        var previousCuisineId = CuisineId;

        await base.SetParametersAsync(parameters);

        if (CuisineId != previousCuisineId)
        {
            await LoadRecipesAsync();
        }
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        StateHasChanged();

        try
        {
            var result = await RecipeService.GetByCuisineAsync(CuisineId, token);

            if (token.IsCancellationRequested)
                return;

            _recipes = result;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was intentionally cancelled — nothing to do.
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private async Task Retry()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        if (!_disposed)
        {
            _disposed = true;
            _cts?.Cancel();
            _cts?.Dispose();
        }
    }
}

