using sv_875e10040b0f4dbdb6f581e78b168275.Models;

namespace sv_875e10040b0f4dbdb6f581e78b168275.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> _data = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Neapolitan pizza with fresh mozzarella, basil, and San Marzano tomatoes.", 30),
            new(2, "Pasta Carbonara", "Creamy Roman pasta with guanciale, Pecorino Romano, and black pepper.", 25),
            new(3, "Risotto alla Milanese", "Saffron-infused Arborio rice cooked slowly in broth with Parmigiano-Reggiano.", 45),
            new(4, "Tiramisu", "Layered dessert of espresso-soaked ladyfingers and mascarpone cream.", 40),
        },
        [2] = new List<Recipe>
        {
            new(5, "Kung Pao Chicken", "Spicy stir-fried chicken with peanuts, Sichuan peppercorns, and dried chili peppers.", 35),
            new(6, "Mapo Tofu", "Silken tofu in a fiery sauce of doubanjiang, fermented black beans, and ground pork.", 20),
            new(7, "Xiaolongbao", "Steamed soup dumplings filled with seasoned pork and rich broth.", 90),
        },
        [3] = new List<Recipe>
        {
            new(8, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion on corn tortillas.", 60),
            new(9, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(10, "Churros", "Fried dough pastries coated in cinnamon sugar, served with chocolate sauce.", 35),
            new(11, "Pozole Rojo", "Hearty hominy stew with pork in a rich guajillo and ancho chili broth.", 120),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (_data.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

